const sel = $('#cyclo-n'), svg = $('#cyclo-svg'), meta = $('#cyclo-meta'), out = $('#cyclo-out');
const NS = [3,4,5,6,7,8,9,10,12,15,16,20,24];
for(const n of NS){
  const o = document.createElement('option'); o.value=n; o.textContent='n='+n;
  sel.appendChild(o);
}
sel.value = 12;

function subgroupsOfUnits(n){
  // list subgroups of (Z/nZ)^* by enumerating subsets closed under *, containing 1
  const units = [];
  for(let a=1;a<n;a++) if(gcd(a,n)===1) units.push(a);
  const U = units.length;
  // enumerate cyclic subgroups, then close under products
  const subs = new Map(); // key = sorted list
  function key(S){ return [...S].sort((a,b)=>a-b).join(','); }
  function close(seed){
    const S = new Set([1]);
    const stack = [...seed];
    while(stack.length){
      const x = stack.pop();
      if(S.has(x)) continue;
      S.add(x);
      for(const y of [...S]){
        const p = mod(x*y, n);
        if(!S.has(p)) stack.push(p);
      }
    }
    return S;
  }
  subs.set('1', new Set([1]));
  for(const a of units){
    const S = close([a]);
    subs.set(key(S), S);
  }
  // close under pairwise joins a few times
  let changed = true, guard=0;
  while(changed && guard<6){
    changed=false; guard++;
    const ks = [...subs.keys()];
    for(let i=0;i<ks.length;i++) for(let j=i;j<ks.length;j++){
      const A = subs.get(ks[i]), B = subs.get(ks[j]);
      const seed = [...A, ...B];
      const S = close(seed);
      const k = key(S);
      if(!subs.has(k)){ subs.set(k, S); changed=true; }
    }
  }
  return [...subs.values()].sort((a,b)=>a.size-b.size);
}

function fixedFieldName(n, H){
  // symbolic name for fixed field of H in Q(zeta_n)
  const hs = [...H].sort((a,b)=>a-b);
  if(hs.length===1 && hs[0]===1) return `Q(ζ_${n})`;
  const phi = eulerPhi(n);
  if(hs.length === phi) return `Q`;
  // degree over Q
  const deg = phi / hs.length;
  return `K_${deg} (fix of {${hs.join(',')}})`;
}

function render(){
  const n = parseInt(sel.value, 10);
  const phi = eulerPhi(n);
  meta.textContent = `[Q(ζ_${n}):Q] = φ(${n}) = ${phi}`;
  svg.innerHTML = '';
  const subs = subgroupsOfUnits(n);
  // Draw Hasse-like diagram: top Q(ζ_n), bottom Q; levels by subgroup size
  const W = 620, H = 340;
  const byLevel = new Map();
  for(const S of subs){
    const lvl = S.size; // bigger subgroup = smaller field
    if(!byLevel.has(lvl)) byLevel.set(lvl, []);
    byLevel.get(lvl).push(S);
  }
  const levels = [...byLevel.keys()].sort((a,b)=>a-b);
  const yTop = 40, yBot = H - 40;
  const pos = new Map(); // key -> [x,y]
  levels.forEach((lvl, i) => {
    const row = byLevel.get(lvl);
    const y = yTop + (yBot - yTop) * (i/(Math.max(1, levels.length-1)));
    const m = row.length;
    row.forEach((S, j) => {
      const x = 60 + (W - 120) * ((j+1)/(m+1));
      const k = [...S].sort((a,b)=>a-b).join(',');
      pos.set(k, [x,y,S]);
    });
  });
  // edges: A covers B if A ⊂ B properly and no intermediate
  const keys = [...pos.keys()];
  for(let i=0;i<keys.length;i++){
    const [xa,ya,A] = pos.get(keys[i]);
    for(let j=0;j<keys.length;j++){
      if(i===j) continue;
      const [xb,yb,B] = pos.get(keys[j]);
      if(A.size >= B.size) continue;
      let contained = true;
      for(const x of A) if(!B.has(x)){ contained = false; break; }
      if(!contained) continue;
      // check no intermediate
      let maximal = true;
      for(let k=0;k<keys.length;k++){
        if(k===i||k===j) continue;
        const [,,C] = pos.get(keys[k]);
        if(C.size <= A.size || C.size >= B.size) continue;
        let cA = true; for(const x of A) if(!C.has(x)){ cA=false; break; }
        if(!cA) continue;
        let cB = true; for(const x of C) if(!B.has(x)){ cB=false; break; }
        if(cB){ maximal=false; break; }
      }
      if(maximal){
        const line = SVG('line',{x1:xa,y1:ya,x2:xb,y2:yb,stroke:'var(--line)','stroke-width':1.2});
        svg.appendChild(line);
      }
    }
  }
  // nodes
  for(const k of keys){
    const [x,y,S] = pos.get(k);
    const name = fixedFieldName(n, S);
    const isTop = (S.size === 1);
    const isBot = (S.size === phi);
    const color = isTop ? 'var(--yellow)' : (isBot ? 'var(--green)' : 'var(--blue)');
    const rect = SVG('rect', {x:x-56, y:y-14, width:112, height:28, rx:6, ry:6,
      fill:'var(--panel2)', stroke:color, 'stroke-width':1.4});
    svg.appendChild(rect);
    const t = SVG('text',{x, y:y+4, 'text-anchor':'middle','font-size':12, fill:'#fff'});
    t.textContent = name;
    svg.appendChild(t);
  }
  // annotate degrees along tree from top to cover
  // readout
  const abelian = `(Z/${n}Z)* has order ${phi}; all ${subs.length} subgroups of it correspond bijectively to subfields of Q(ζ_${n}).`;
  out.textContent = abelian;
}
sel.addEventListener('change', render);
render();

