  const grid = $('#clsvis-grid'), out = $('#clsvis-out'), svg = $('#clsvis-svg');

  // Draw an SVG scatter: x = |d|, y = h_K, colored by class number
  (function drawScatter(){
    const W = 620, Hh = 200, padL = 40, padR = 20, padT = 20, padB = 30;
    const xMax = 100, yMax = 12;
    const ax = (dd) => padL + (Math.abs(dd)-1)/(xMax-1) * (W - padL - padR);
    const ay = (hh) => (Hh - padB) - (hh-1)/(yMax-1) * (Hh - padT - padB);
    // axes
    svg.appendChild(SVG('line',{x1:padL, y1:Hh-padB, x2:W-padR, y2:Hh-padB, stroke:'var(--line)', 'stroke-width':1}));
    svg.appendChild(SVG('line',{x1:padL, y1:padT, x2:padL, y2:Hh-padB, stroke:'var(--line)', 'stroke-width':1}));
    // x ticks every 20
    for(let x=20;x<=100;x+=20){
      const px = ax(-x);
